import { useState, useEffect, useCallback } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  where,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  writeBatch,
  getDocs,
  setDoc,
  getDoc,
  arrayUnion,
  arrayRemove
} from 'firebase/firestore';
import { UserData, Role, Notification, AdminNote } from '../../types/appTypes';

export const useSystemData = () => {
  const [users, setUsers] = useState<UserData[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [adminNotes, setAdminNotes] = useState<AdminNote[]>([]);

  useEffect(() => {
    const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
    const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
    const unsubNotifications = onSnapshot(collection(db, 'notifications'), s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification))));

    const unsubAdminNotes = onSnapshot(doc(db, 'settings', 'notes'), (s) => {
      if (s.exists()) {
        const d = s.data();
        setAdminNotes(Array.isArray(d.items) ? d.items : []);
      } else {
        setAdminNotes([]);
      }
    });

    return () => { 
        unsubUsers(); unsubRoles(); unsubNotifications(); unsubAdminNotes();
    };
  }, []);

  // --- POMOCNÉ FUNKCIE (STABILNÉ) ---

  const resolveName = useCallback((username?: string | null) => {
    if (!username) return '-';
    const u = users.find(x => x.username === username);
    return (u?.nickname || username).toUpperCase();
  }, [users]);

  const onVerifyAdminPassword = useCallback((password: string) => {
      const admin = users.find(u => u.username.toUpperCase() === 'ADMIN');
      return admin ? admin.password === password : false;
  }, [users]);

  // --- AKCIE ---

  const onAddUser = async (user: UserData) => { await addDoc(collection(db, 'users'), user); };

  const onUpdatePassword = async (username: string, newPass: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { password: newPass }));
  };

  const onUpdateNickname = async (username: string, newNick: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { nickname: newNick }));
  };

  const onUpdateUserRole = async (username: string, newRole: string) => {
    if (username.toUpperCase() === 'ADMIN') return;
    try {
        const q = query(collection(db, 'users'), where('username', '==', username));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.forEach(d => batch.update(d.ref, { role: newRole }));
        await batch.commit();
    } catch (e) { console.error("Error updating user role", e); }
  };

  const onUpdateExportPermission = async (username: string, canExport: boolean) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { canExportAnalytics: canExport }));
  };

  const onDeleteUser = async (username: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => deleteDoc(d.ref));
  };

  const onAddRole = async (name: string, parentId?: string, rank: number = 5) => {
    try { 
      await addDoc(collection(db, 'roles'), { 
        name: name.toUpperCase(), 
        parentId: parentId || null, 
        rank: rank, 
        isSystem: false,
        permissions: [] 
      }); 
    } catch (e) { console.error(e); }
  };

  const onDeleteRole = async (id: string) => {
    try {
        await deleteDoc(doc(db, 'roles', id));
    } catch (e) { console.error(e); }
  };

  const onUpdatePermission = async (permissionName: string, roleName: string, hasPermission: boolean) => {
    const role = roles.find(r => r.name === roleName);
    if (!role) return;
    const roleRef = doc(db, 'roles', role.id);

    try {
        if (hasPermission) {
            await updateDoc(roleRef, { permissions: arrayUnion(permissionName) });
        } else {
            await updateDoc(roleRef, { permissions: arrayRemove(permissionName) });
        }
    } catch (e) { console.error("Error updating permission", e); }
  };

  const onAddNotification = async (notification: Partial<Notification>) => {
    try { await addDoc(collection(db, 'notifications'), { ...notification, timestamp: Date.now() }); }
    catch (e) { console.error("Error adding notification", e); }
  };

  const onClearNotification = async (id: string) => {
    try { await deleteDoc(doc(db, 'notifications', id)); } catch (e) { console.error("Error clearing notification", e); }
  };

  const onBroadcastNotification = async (message: string, author: string, targetUsernames?: string[]) => {
    try {
      const batch = writeBatch(db);
      const recipients = targetUsernames && targetUsernames.length > 0 
        ? users.filter(u => targetUsernames.includes(u.username))
        : users;

      recipients.forEach(user => {
        const notifRef = doc(collection(db, 'notifications'));
        batch.set(notifRef, {
          partNumber: 'SYSTÉMOVÁ SPRÁVA',
          reason: message,
          reportedBy: author,
          targetUser: user.username,
          timestamp: Date.now()
        });
      });
      await batch.commit();
    } catch (e) {
      console.error("Broadcast failed", e);
    }
  };

  const onAddAdminNote = async (text: string, author: string) => {
      try {
          const newItem: AdminNote = { id: crypto.randomUUID(), text, author, createdAt: Date.now() };
          await setDoc(doc(db, 'settings', 'notes'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onDeleteAdminNote = async (id: string) => {
      try {
          const ref = doc(db, 'settings', 'notes');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = (snap.data().items || []) as AdminNote[];
              const newItems = currentItems.filter(i => i.id !== id);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };

  const onClearAdminNotes = async () => {
      try {
          await updateDoc(doc(db, 'settings', 'notes'), { items: [] });
      } catch (e) { console.error(e); }
  };

  return {
    users, roles, notifications, adminNotes,
    resolveName, onVerifyAdminPassword,
    onAddUser, onUpdatePassword, onUpdateNickname, onUpdateUserRole, onUpdateExportPermission, onDeleteUser,
    onAddRole, onDeleteRole, onUpdatePermission,
    onAddNotification, onClearNotification, onBroadcastNotification,
    onAddAdminNote, onDeleteAdminNote, onClearAdminNotes
  };
};

import React, { useMemo } from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import NotificationModal from './components/modals/NotificationModal';
import { useData } from './context/DataContext';
import { SystemConfig } from './types/appTypes';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  // Získanie notifikácií pre aktuálneho používateľa
  const myNotifications = useMemo(() => {
      if (!data || !data.notifications) return [];
      return data.notifications
        .filter(n => n.targetUser === props.currentUser)
        .sort((a, b) => b.timestamp - a.timestamp);
  }, [data?.notifications, props.currentUser]);

  const activeNotification = myNotifications.length > 0 ? myNotifications[0] : null;

  const handleConfirmNotification = () => {
      if (activeNotification && data.onClearNotification) {
          data.onClearNotification(activeNotification.id);
      }
  };

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = data.onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          // Explicitné namapovanie funkcií z hookov
          onAddTask={data.onAddTask}
          onUpdateTask={data.onUpdateTask}
          onDeleteTask={data.onDeleteTask}
          onToggleTask={data.onToggleTask}
          onToggleBlock={data.onToggleBlock}
          onToggleManualBlock={data.onToggleManualBlock}
          onExhaustSearch={data.onExhaustSearch}
          onAddNote={data.onAddNote}
          onMarkAsIncorrect={data.onMarkAsIncorrect}
          onStartAudit={data.onStartAudit}
          onFinishAudit={data.onFinishAudit}
          onToggleMissing={data.onToggleMissing}
          onDeleteMissingItem={(id) => data.onToggleMissing(id)}
          resolveName={data.resolveName}

          // Scrap Weighing Lifecycle
          onFinalizeScrapArchive={data.onFinalizeScrapArchive}
          onBulkAddScrapRecords={data.onBulkAddScrapRecords}
          onUpdateScrapRecord={data.onUpdateScrapRecord}
          onUpdateArchivedScrapItem={data.onUpdateArchivedScrapItem}
          onUpdateScrapArchive={data.onUpdateScrapArchive}
          onExpediteScrap={data.onExpediteScrap}

          // Maintenance & System
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}

          // Data
          draftTasks={data.draftTasks || []}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}

          // Props from Parent
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}

          // Admin Notes
          adminNotes={data.adminNotes || []}
          onAddAdminNote={data.onAddAdminNote}
          onDeleteAdminNote={data.onDeleteAdminNote}
          onClearAdminNotes={data.onClearAdminNotes}
        />

        {activeNotification && (
            <NotificationModal 
                notification={activeNotification}
                onConfirm={handleConfirmNotification}
                resolveName={data.resolveName}
            />
        )}
    </div>
  );
};

