  id: string;
  partNumber: string;
  text?: string;
  workplace?: string;
  quantity: string;
  quantityUnit?: 'pcs' | 'boxes' | 'pallet';
  priority: PriorityLevel;
  isDone: boolean;
  isInProgress: boolean;
  inProgressBy?: string | null;
  createdBy?: string | null;
  createdAt: number;
  /* Fix: Added startedAt property which was missing and caused type errors in analytics and task handling */
  startedAt?: number | null;
  completedBy?: string | null;
  completedAt?: number | null;
  isLogistics?: boolean;
  isProduction?: boolean;
  isActivity?: boolean;
  isMissing?: boolean;
  missingReason?: string | null;
  missingReportedBy?: string | null;
  note?: string;
  plate?: string;
  isBlocked?: boolean;
  blockedBy?: string | null;
  isManualBlocked?: boolean;
  searchExhausted?: boolean;
  searchedBy?: string | null;
  isAuditInProgress?: boolean;
  auditBy?: string | null;
  auditResult?: 'OK' | 'NOK' | null;
  auditNote?: string;
  auditedBy?: string | null;
  auditedAt?: number | null;
  auditFinalBadge?: string;
  sourceSectorId?: string | null;
  targetSectorId?: string | null;
  pickedFromSectorId?: string | null;
  inventoryHistory?: { start: number; end?: number }[];
  standardTime?: number;
  status: string;
